const projectImagesGlob = import.meta.glob('../assets/projects/**/*.{png,jpg,jpeg,svg,webp}', { eager: true, import: 'default' });

function enhanceProjectWithLocalImages(project) {
  const matchingKeys = Object.keys(projectImagesGlob).filter(key => {
    const keyLower = key.toLowerCase();
    const slugLower = (project.slug || '').toLowerCase();
    return keyLower.includes(`/projects/${slugLower}/`) ||
      keyLower.includes(`/projects/${slugLower.replace(/-/g, ' ')}/`) ||
      keyLower.includes(`/projects/${slugLower.replace(/ /g, '-')}/`);
  });

  if (matchingKeys.length === 0) {
    return project;
  }

  // Ensure hero.png or cover.png comes first, then sort alphanumeric (e.g. 1.png, 2.png, 3.png or about.png)
  matchingKeys.sort((a, b) => {
    const aLower = a.toLowerCase();
    const bLower = b.toLowerCase();
    const isAHero = aLower.includes('/hero.') || aLower.includes('/cover.');
    const isBHero = bLower.includes('/hero.') || bLower.includes('/cover.');
    if (isAHero && !isBHero) return -1;
    if (!isAHero && isBHero) return 1;
    return a.localeCompare(b, undefined, { numeric: true });
  });

  const loadedUrls = matchingKeys.map(key => projectImagesGlob[key]);
  const cover = loadedUrls[0];

  return {
    ...project,
    cover: cover,
    screenshots: loadedUrls
  };
}

export const projectsData = rawProjectsData.map(enhanceProjectWithLocalImages);

export const categoriesList = [
  "All",
  ...Array.from(new Set(rawProjectsData.map(project => project.category))).filter(Boolean)
];

